const body = $json.body ?? $json;
const parseArray = (value) => {
  if (Array.isArray(value)) return value.filter(Boolean).map((v) => String(v).trim()).filter(Boolean);
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return [];
    try {
      const parsed = JSON.parse(trimmed);
      if (Array.isArray(parsed)) return parsed.filter(Boolean).map((v) => String(v).trim()).filter(Boolean);
    } catch (_) {}
    return trimmed.split(',').map((v) => v.trim()).filter(Boolean);
  }
  return [];
};
const firstNonEmpty = (...values) => {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    if (typeof value === 'string' && value.trim() === '') continue;
    return value;
  }
  return null;
};
const toInt = (value, fallback = null) => {
  if (value === null || value === undefined || value === '') return fallback;
  const num = Number(value);
  return Number.isFinite(num) ? Math.trunc(num) : fallback;
};
const normalizePlanKey = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (!raw) return 'starter';
  if (['starter', 'start', 'basic'].includes(raw)) return 'starter';
  if (['growth', 'grow'].includes(raw)) return 'growth';
  if (['pro', 'professional'].includes(raw)) return 'pro';
  return raw;
};
const planLimits = { starter: 15, growth: 25, pro: 40 };
const directionFromLocale = (locale) => String(locale || '').toLowerCase().startsWith('ar') ? 'rtl' : 'ltr';
const rawLocale = String(firstNonEmpty(body.locale, body.language, body.lang, body.userLanguage, 'en') || 'en').trim();
const locale = rawLocale.toLowerCase().startsWith('ar') ? 'ar' : 'en';
const textDirection = String(firstNonEmpty(body.textDirection, body.direction, directionFromLocale(locale)) || directionFromLocale(locale)).toLowerCase() === 'rtl' ? 'rtl' : 'ltr';

const context = body.context && typeof body.context === 'object' ? body.context : {};
const dbContext = body.dbContext && typeof body.dbContext === 'object' ? body.dbContext : {};
const dbPlan = body.plan && typeof body.plan === 'object' ? body.plan : {};

const modeRaw = String(firstNonEmpty(body.mode, body.action, '') || '').trim().toLowerCase();
const mode = ['improve_existing', 'create_new', 'use_current'].includes(modeRaw) ? modeRaw : '';

const originalPrompt = String(firstNonEmpty(
  body.originalPrompt,
  body.original_prompt,
  dbContext.promptCellValue,
  body.currentPrompt,
  ''
) || '').trim();

const goal = String(firstNonEmpty(body.goal, body.agentGoal, body.whatShouldThisAgentDo, '') || '').trim();
const business = String(firstNonEmpty(body.business, body.businessType, body.businessDescription, '') || '').trim();
const tone = String(firstNonEmpty(body.tone, body.style, body.voice, '') || '').trim();
const language = String(firstNonEmpty(body.languagePreference, body.languageChoice, body.promptLanguage, body.language, locale) || locale).trim();
const collectFields = parseArray(firstNonEmpty(body.collectFields, body.collect, body.collect_fields, []));
const avoidRules = parseArray(firstNonEmpty(body.avoidRules, body.avoid, body.avoid_rules, []));
const importantNote = String(firstNonEmpty(body.importantNote, body.note, body.notes, '') || '').trim();

const planKey = normalizePlanKey(firstNonEmpty(
  dbPlan.key,
  body.planKey,
  body.plan_key,
  dbContext.planKey,
  dbContext.subscriptionPlan,
  'starter'
));
const dailyLimit = toInt(firstNonEmpty(dbPlan.dailyLimit, body.dailyLimit, body.daily_limit, dbContext.dailyLimit, planLimits[planKey]), planLimits[planKey] ?? 15);
const dailyUsed = Math.max(0, toInt(firstNonEmpty(dbPlan.dailyUsed, body.dailyUsed, body.daily_used, dbContext.dailyUsed, dbContext.promptAssistantDailyUsed, 0), 0));
const dailyRemaining = Math.max(dailyLimit - dailyUsed, 0);
const isBlocked = dailyUsed >= dailyLimit;

const workspaceId = firstNonEmpty(context.workspaceId, body.workspaceId, body.workspace_id, dbContext.workspaceId);
const agentId = firstNonEmpty(context.agentId, body.agentId, body.agent_id, dbContext.agentId);
const agentTabId = firstNonEmpty(context.agentTabId, body.agentTabId, body.agent_tab_id, dbContext.agentTabId);
const agentTabKey = firstNonEmpty(context.agentTabKey, body.agentTabKey, body.agent_tab_key, dbContext.agentTabKey);
const agentTabLabel = firstNonEmpty(context.agentTabLabel, body.agentTabLabel, body.agent_tab_label, dbContext.agentTabLabel);

let route = 'generate';
let errorCode = null;
let errorMessage = null;

if (!mode) {
  route = 'direct';
  errorCode = 'missing_mode';
  errorMessage = 'mode must be one of improve_existing, create_new, or use_current';
} else if (mode === 'improve_existing' && !originalPrompt) {
  route = 'direct';
  errorCode = 'missing_original_prompt';
  errorMessage = 'originalPrompt is required for improve_existing';
} else if (mode === 'use_current') {
  route = 'direct';
} else if (isBlocked) {
  route = 'direct';
  errorCode = 'daily_limit_reached';
  errorMessage = 'Daily prompt assistant limit reached for this plan';
}

const missingFields = [];
if (mode === 'create_new') {
  if (!goal) missingFields.push('goal');
  if (!business) missingFields.push('business');
  if (!tone) missingFields.push('tone');
  if (!language) missingFields.push('language');
}

const requestId = (globalThis.crypto?.randomUUID?.() ?? `req_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`);

return {
  json: {
    requestId,
    receivedAt: new Date().toISOString(),
    mode,
    route,
    errorCode,
    errorMessage,
    locale,
    textDirection,
    originalPrompt,
    goal,
    business,
    tone,
    language,
    collectFields,
    avoidRules,
    importantNote,
    missingFields,
    planKey,
    dailyLimit,
    dailyUsed,
    dailyRemaining,
    isBlocked,
    context: {
      workspaceId,
      agentId,
      agentTabId,
      agentTabKey,
      agentTabLabel,
    },
    dbContext: {
      promptSource: firstNonEmpty(dbContext.promptSource, body.promptSource),
      promptRowId: firstNonEmpty(dbContext.promptRowId, body.promptRowId),
      promptColumn: firstNonEmpty(dbContext.promptColumn, body.promptColumn),
      promptCellValue: firstNonEmpty(dbContext.promptCellValue, body.promptCellValue, originalPrompt),
    }
  }
};

const pickLanguageInstruction = (value) => {
  const raw = String(value || '').toLowerCase();
  if (raw.includes('arabic') || raw.includes('ar') || raw.includes('عربي')) return 'Arabic';
  if (raw.includes('english') || raw.includes('en')) return 'English';
  if (raw.includes('same')) return 'Same as the customer/user input language';
  if (raw.includes('+')) return 'Arabic and English when appropriate';
  return value || 'Preserve the user language';
};

const chatInput = [
  `Mode: ${$json.mode}`,
  `Locale: ${$json.locale}`,
  `Text direction: ${$json.textDirection}`,
  `Plan: ${$json.planKey}`,
  `Workspace ID: ${$json.context?.workspaceId || ''}`,
  `Agent ID: ${$json.context?.agentId || ''}`,
  `Agent Tab ID: ${$json.context?.agentTabId || ''}`,
  `Agent Tab Key: ${$json.context?.agentTabKey || ''}`,
  `Agent Tab Label: ${$json.context?.agentTabLabel || ''}`,
  `Original prompt:`,
  $json.originalPrompt || '',
  ``,
  `Goal: ${$json.goal || ''}`,
  `Business: ${$json.business || ''}`,
  `Tone: ${$json.tone || ''}`,
  `Language preference: ${pickLanguageInstruction($json.language)}`,
  `Collect fields: ${(Array.isArray($json.collectFields) ? $json.collectFields.join(', ') : '') || 'None'}`,
  `Avoid rules: ${(Array.isArray($json.avoidRules) ? $json.avoidRules.join(', ') : '') || 'None'}`,
  `Important note: ${$json.importantNote || ''}`,
  `Missing fields: ${(Array.isArray($json.missingFields) ? $json.missingFields.join(', ') : '') || 'None'}`,
  ``,
  `Return strict JSON only.`
].join('\n');

return {
  json: {
    ...$json,
    chatInput,
  }
};

const base = $('Prepare Chat Input').item.json;
const raw = String($json.output ?? $json.text ?? $json.response ?? '').trim();

let parsed = null;
try {
  parsed = JSON.parse(raw);
} catch (_) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (_) {}
  }
}

const finalPrompt = String(parsed?.finalPrompt || base.originalPrompt || '').trim();
const summary = String(parsed?.summary || '').trim() || (base.locale === 'ar'
  ? 'تم إنشاء مسودة برومبت جديدة جاهزة للمراجعة.'
  : 'A new prompt draft was generated and is ready for review.');

const questions = Array.isArray(parsed?.questions)
  ? parsed.questions.map((q) => String(q).trim()).filter(Boolean).slice(0, 4)
  : [];

const aiMissing = Array.isArray(parsed?.missingFields)
  ? parsed.missingFields.map((q) => String(q).trim()).filter(Boolean)
  : [];

return {
  json: {
    success: true,
    status: 'ok',
    modeApplied: base.mode,
    originalPrompt: base.originalPrompt || '',
    finalPrompt,
    summary,
    missingFields: Array.from(new Set([...(base.missingFields || []), ...aiMissing])),
    questions,
    canApply: true,
    canCopy: !!finalPrompt,
    canRegenerate: true,
    locale: base.locale,
    textDirection: base.textDirection,
    limit: {
      planKey: base.planKey,
      dailyLimit: base.dailyLimit,
      dailyUsed: base.dailyUsed,
      dailyRemaining: Math.max(base.dailyRemaining - 1, 0),
      blocked: false,
    },
    requestId: base.requestId,
    context: base.context,
    dbContext: base.dbContext,
    workflowVersion: 'prompt-assistant-v1'
  }
};
